func (i Taxonomy) Alphabetical() OrderedTaxonomy {
	ia := i.TaxonomyArray()
	p := ia.getOneOPage()
	if p == nil {
		return ia
	}
	currentSite := p.Site().Current()
	coll := langs.GetCollator1(currentSite.Language())
	coll.Lock()
	defer coll.Unlock()
	name := func(i1, i2 *OrderedTaxonomyEntry) bool {
		return coll.CompareStrings(i1.Name, i2.Name) < 0
	}
	oiBy(name).Sort(ia)
	return ia
}
